// Safety poll logic to wait for Wails runtime to be fully initialized
function runWhenReady(fn) {
    if (window.go && window.go.main && window.go.main.App) {
        fn();
    } else {
        setTimeout(() => runWhenReady(fn), 30);
    }
}

runWhenReady(() => {
    loadDashboard();
    loadLogs();
    loadSettingsLogs();
    
    // Poll stats
    setInterval(() => { loadDashboard(); loadLogs(); loadSettingsLogs(); }, 5000);
});
